mapper.select:
SELECT ITEM_NAME AS "itemName", QUANTITY AS "quantity", WEIGHT AS "weight" FROM ( SELECT 'IMPORT' AS DECLARE_TYPE, ITEM.IDI_SN AS ITEM_NO, ITEM.IDI_DCLR_GDSNM AS ITEM_NAME, TO_CHAR(ITEM.IDI_QTY, 'FM999,999,999') AS QUANTITY, TO_CHAR(ITEM.IDI_NET_WT, 'FM999,999,999.000') AS WEIGHT FROM IMP_DCLR_ITEM ITEM WHERE ITEM.IDI_IR_NO = #{reqNo}
UNION ALL
SELECT 'EXPORT' AS DECLARE_TYPE, ITEM.EDI_SN AS ITEM_NO, ITEM.EDI_EXPT_GDS_NM AS ITEM_NAME, TO_CHAR(ITEM.EDI_DCLR_QTY, 'FM999,999,999') AS QUANTITY, TO_CHAR(ITEM.EDI_NET_WT, 'FM999,999,999.000') AS WEIGHT FROM EXP_DCLR_ITEM ITEM WHERE ITEM.EDI_ER_NO = #{reqNo} ) WHERE (#{declareType} IS NULL OR #{declareType} = 'ALL' OR DECLARE_TYPE = #{declareType}) ORDER BY ITEM_NO
